// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract BlockCertificate {
    address public admin;
    mapping(bytes32 => bool) public certificateExists;
    mapping(bytes32 => string) public studentProfiles;
    
    event CertificateIssued(bytes32 indexed hashKey, string studentProfile);

    constructor() {
        admin = msg.sender;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can issue");
        _;
    }

    // Generate hash from cert + ALL student data
    function generateHash(
        bytes calldata certData,
        string memory name,
        string memory rollNumber,
        string memory course,
        string memory year,
        string memory institution
    ) public pure returns (bytes32) {
        return keccak256(abi.encodePacked(certData, name, rollNumber, course, year, institution));
    }

    // YOUR DIAGRAM FLOW EXACTLY
    function issueCertificate(
        bytes calldata certData,
        string memory name,
        string memory rollNumber,
        string memory course,
        string memory year,
        string memory institution
    ) public onlyAdmin {
        bytes32 hashKey = generateHash(certData, name, rollNumber, course, year, institution);
        
        // CHECK: Does hash exist?
        require(!certificateExists[hashKey], "Certificate already exists");
        
        // STORE
        string memory profile = string(abi.encodePacked(
            name, "|", rollNumber, "|", course, "|", year, "|", institution
        ));
        certificateExists[hashKey] = true;
        studentProfiles[hashKey] = profile;
        
        emit CertificateIssued(hashKey, profile);
    }

    function verifyHash(bytes32 hashKey) public view returns (bool exists, string memory profile) {
        exists = certificateExists[hashKey];
        profile = studentProfiles[hashKey];
    }
}

